import{_ as i,C as A,o as e,c as p,a5 as s,b as l,w as a,a as r,E,a4 as o}from"./chunks/framework.sOZL8giL.js";const _=JSON.parse('{"title":"为什么需要评估","description":"","frontmatter":{},"headers":[],"relativePath":"06-Agent评估/01-为什么需要评估.md","filePath":"06-Agent评估/01-为什么需要评估.md","lastUpdated":1774181700000}'),d={name:"06-Agent评估/01-为什么需要评估.md"};function B(h,t,u,b,g,c){const n=A("Mermaid");return e(),p("div",null,[t[2]||(t[2]=s('<h1 id="为什么需要评估" tabindex="-1">为什么需要评估 <a class="header-anchor" href="#为什么需要评估" aria-label="Permalink to &quot;为什么需要评估&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 6 模块的第 1 章。</p></blockquote><p>Agent 不是自动贩卖机——同样的输入每次可能产出不同的结果。怎么衡量这种随机性？</p><hr><h2 id="评估的本质" tabindex="-1">评估的本质 <a class="header-anchor" href="#评估的本质" aria-label="Permalink to &quot;评估的本质&quot;">​</a></h2><p>传统软件测试很简单：输入 A，预期输出 B，运行检查是否等于 B。但 Agent 是概率性的——给定输入 A，它可能产出 B、C 或 D。每次运行的路径可能不同。</p><p>这意味着你不能用传统软件的&quot;等于/不等于&quot;来判断 Agent 的输出。你需要一套全新的评估方法。</p><p>评估的三元组：<strong>输入（Input）+ 输出（Output）+ 评分器（Grader）</strong>。你给 Agent 一个输入，它产生一个输出，评分器判断输出是否满足要求。</p><p>关键区别：传统测试的评分器是&quot;等于&quot;，Agent 评估的评分器可以是&quot;代码能运行&quot;&quot;格式正确&quot;&quot;覆盖了所有要点&quot;——更灵活但也更难实现。</p>',9)),(e(),l(o,null,{default:a(()=>[E(n,{id:"mermaid-27",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E8%AF%84%E4%BC%B0%E4%B8%89%E5%85%83%E7%BB%84%5D%20--%3E%20B%5BInput%20%E8%BE%93%E5%85%A5%3Cbr%2F%3E%E7%BB%99%20Agent%20%E7%9A%84%E4%BB%BB%E5%8A%A1%5D%0A%20%20%20%20A%20--%3E%20C%5BOutput%20%E8%BE%93%E5%87%BA%3Cbr%2F%3EAgent%20%E7%9A%84%E5%9B%9E%E7%AD%94%5D%0A%20%20%20%20A%20--%3E%20D%5BGrader%20%E8%AF%84%E5%88%86%E5%99%A8%3Cbr%2F%3E%E5%88%A4%E6%96%AD%E8%B4%A8%E9%87%8F%5D%0A%20%20%20%20B%20--%3E%20E%5B%E4%BC%A0%E7%BB%9F%E6%B5%8B%E8%AF%95%5D%0A%20%20%20%20C%20--%3E%20E%0A%20%20%20%20D%20--%3E%20E%0A%20%20%20%20E%20--%3E%20F%5B%E8%AF%84%E5%88%86%E5%99%A8%20%3D%20%22%E7%AD%89%E4%BA%8E%22%3Cbr%2F%3E%E7%A1%AE%E5%AE%9A%E6%80%A7%E5%88%A4%E6%96%AD%5D%0A%20%20%20%20A%20--%3E%20G%5BAgent%20%E8%AF%84%E4%BC%B0%5D%0A%20%20%20%20C%20--%3E%20G%0A%20%20%20%20D%20--%3E%20G%0A%20%20%20%20G%20--%3E%20H%5B%E8%AF%84%E5%88%86%E5%99%A8%20%3D%20%E7%81%B5%E6%B4%BB%E6%A0%87%E5%87%86%3Cbr%2F%3E%E4%BB%A3%E7%A0%81%E8%83%BD%E8%BF%90%E8%A1%8C%2F%E6%A0%BC%E5%BC%8F%E6%AD%A3%E7%A1%AE%2F%E8%A6%86%E7%9B%96%E8%A6%81%E7%82%B9%5D%0A%20%20%20%20style%20F%20fill%3A%23ddd%0A%20%20%20%20style%20H%20fill%3A%238cf%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[r(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=s(`<blockquote><p>💡 <strong>图解：</strong> Agent 评估的核心难点不在&quot;输入&quot;和&quot;输出&quot;，而在&quot;评分器&quot;——概率性输出需要概率性评估。</p></blockquote><hr><h2 id="驯服随机性" tabindex="-1">驯服随机性 <a class="header-anchor" href="#驯服随机性" aria-label="Permalink to &quot;驯服随机性&quot;">​</a></h2><p>LLM 的输出质量不稳定。同一个问题问 10 次，可能有 3 次很好、5 次一般、2 次很差。你怎么衡量这种随机性？</p><h3 id="pass-k" tabindex="-1">Pass@k <a class="header-anchor" href="#pass-k" aria-label="Permalink to &quot;Pass@k&quot;">​</a></h3><p>给一个问题，生成 k 个答案，至少有一个通过评估就算 Pass。这衡量的是&quot;能力上限&quot;——模型在最好情况下能做多好。</p><p>比如 Pass@5 = 90% 意味着：生成 5 个答案，90% 的概率至少有一个是对的。</p><p><strong>适用场景</strong>：代码生成——你不在意模型第一次就写对，只要 5 次尝试内能写对就行。</p><h3 id="pass-k-1" tabindex="-1">Pass^k <a class="header-anchor" href="#pass-k-1" aria-label="Permalink to &quot;Pass^k&quot;">​</a></h3><p>给一个问题，生成 k 个答案，全部通过评估才算 Pass。这衡量的是&quot;可靠性下限&quot;——模型在最差情况下不会差到哪去。</p><p>比如 Pass^5 = 70% 意味着：生成 5 个答案，70% 的概率全部都是对的。</p><p><strong>适用场景</strong>：关键决策——你不能容忍任何一个错误答案。</p><h3 id="两者的权衡" tabindex="-1">两者的权衡 <a class="header-anchor" href="#两者的权衡" aria-label="Permalink to &quot;两者的权衡&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>衡量什么</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>Pass@k</strong></td><td>能力上限</td><td>代码生成、探索性任务</td></tr><tr><td><strong>Pass^k</strong></td><td>可靠性下限</td><td>关键决策、生产部署</td></tr></tbody></table><p>大多数场景关注 Pass@k——Agent 可以尝试多次，只要最终能找到正确答案。但关键场景（金融决策、医疗建议）必须关注 Pass^k——不能容忍任何错误。</p><hr><h2 id="为什么需要自动化评估" tabindex="-1">为什么需要自动化评估 <a class="header-anchor" href="#为什么需要自动化评估" aria-label="Permalink to &quot;为什么需要自动化评估&quot;">​</a></h2><p>手动评估不可扩展。一个 Agent 系统每天可能有数千次调用，人工评估每次输出的成本极高。而且人的判断标准不一致——同一次输出，不同评估者可能给出不同分数。</p><p>自动化评估的目标：用代码或模型代替人类来判断输出质量。速度快、成本低、标准一致。</p><p>但自动化评估不是银弹——有些质量维度很难自动化（创造性、审美、价值观）。自动化评估适合有明确标准的场景（正确性、格式、覆盖度）。</p><hr><h2 id="评估的层次" tabindex="-1">评估的层次 <a class="header-anchor" href="#评估的层次" aria-label="Permalink to &quot;评估的层次&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单元评估（单步）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>集成评估（多步）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>端到端评估（完整任务）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>用户满意度评估（真实场景）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><strong>单元评估</strong>：检查单次工具调用或单次 LLM 输出。成本最低、速度最快、但可能遗漏集成问题。</p><p><strong>集成评估</strong>：检查多个步骤的协作。能发现步骤之间的衔接问题。</p><p><strong>端到端评估</strong>：从输入到最终输出的完整流程。最接近真实使用场景，但成本最高、速度最慢。</p><p><strong>用户满意度</strong>：真实用户的反馈。最真实但最难收集和量化。</p><p>从单元评估开始逐步向上。单元评估保证基础质量，集成评估保证协作正确，端到端评估保证整体效果。</p>`,28)),(e(),l(o,null,{default:a(()=>[E(n,{id:"mermaid-142",class:"mermaid",graph:"flowchart%20BT%0A%20%20%20%20A%5B%E7%94%A8%E6%88%B7%E6%BB%A1%E6%84%8F%E5%BA%A6%E8%AF%84%E4%BC%B0%3Cbr%2F%3E%E7%9C%9F%E5%AE%9E%E5%9C%BA%E6%99%AF%20%E6%9C%80%E7%9C%9F%E5%AE%9E%5D%20--%3E%20B%5B%E7%AB%AF%E5%88%B0%E7%AB%AF%E8%AF%84%E4%BC%B0%3Cbr%2F%3E%E5%AE%8C%E6%95%B4%E4%BB%BB%E5%8A%A1%20%E6%9C%80%E5%85%A8%E9%9D%A2%5D%0A%20%20%20%20B%20--%3E%20C%5B%E9%9B%86%E6%88%90%E8%AF%84%E4%BC%B0%3Cbr%2F%3E%E5%A4%9A%E6%AD%A5%E5%8D%8F%E4%BD%9C%5D%0A%20%20%20%20C%20--%3E%20D%5B%E5%8D%95%E5%85%83%E8%AF%84%E4%BC%B0%3Cbr%2F%3E%E5%8D%95%E6%AD%A5%E6%A3%80%E6%9F%A5%20%E6%9C%80%E5%BF%AB%E6%9C%80%E4%BE%BF%E5%AE%9C%5D%0A%20%20%20%20style%20D%20fill%3A%234a9%0A%20%20%20%20style%20C%20fill%3A%236bc%0A%20%20%20%20style%20B%20fill%3A%238cf%0A%20%20%20%20style%20A%20fill%3A%23f96%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[r(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=s('<blockquote><p>💡 <strong>图解：</strong> 评估金字塔从下往上构建——先保证每个零件合格，再看组装，最后看整体使用体验。</p></blockquote><hr><hr><h2 id="⚠️-常见错误" tabindex="-1">⚠️ 常见错误 <a class="header-anchor" href="#⚠️-常见错误" aria-label="Permalink to &quot;⚠️ 常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">❌ 错误做法</th><th style="text-align:left;">✅ 正确做法</th><th style="text-align:left;">为什么</th></tr></thead><tbody><tr><td style="text-align:left;">没有评估就上线</td><td style="text-align:left;">先建评估基准线，再迭代优化</td><td style="text-align:left;">没有评估 = 随机数生成器</td></tr><tr><td style="text-align:left;">只用 Pass@1 评估</td><td style="text-align:left;">同时报告 Pass@k 和 Pass^k</td><td style="text-align:left;">Pass@1 无法反映稳定性</td></tr><tr><td style="text-align:left;">评估数据集不更新</td><td style="text-align:left;">定期刷新评估集，覆盖新场景</td><td style="text-align:left;">模型会过拟合旧评估</td></tr><tr><td style="text-align:left;">评估通过就万事大吉</td><td style="text-align:left;">评估是持续过程</td><td style="text-align:left;">模型会漂移，环境会变化</td></tr></tbody></table><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>Agent 是概率性的，不能用传统&quot;等于/不等于&quot;判断</li><li>评估三元组：输入 + 输出 + 评分器</li><li>Pass@k 衡量能力上限，Pass^k 衡量可靠性下限</li><li>自动化评估不可替代但有局限</li><li>四个层次：单元 → 集成 → 端到端 → 用户满意度</li></ul><hr><p><strong>下一章</strong>: <a href="./02-评分器体系.html">评分器体系</a></p><hr><p><a href="/">← 返回首页</a> | <a href="/05-Skill工程/">← 上一模块: Skill工程</a> | <a href="/07-生产实践/">下一模块: 生产实践 →</a></p>',11))])}const q=i(d,[["render",B]]);export{_ as __pageData,q as default};
